import{_ as a,c as n,o as t,aj as l}from"./chunks/framework.CynFBi0q.js";const c=JSON.parse('{"title":"第5章 机会捕捉：AI 产品市场与需求分析","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-agent-product/chapter_5.md","filePath":"handbook/ai-agent-product/chapter_5.md","lastUpdated":1781970092000}'),p={name:"handbook/ai-agent-product/chapter_5.md"};function i(e,s,r,d,o,u){return t(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="第5章-机会捕捉-ai-产品市场与需求分析" tabindex="-1">第5章 机会捕捉：AI 产品市场与需求分析 <a class="header-anchor" href="#第5章-机会捕捉-ai-产品市场与需求分析" aria-label="Permalink to “第5章 机会捕捉：AI 产品市场与需求分析”">​</a></h1><p>90%的AI产品失败，不是因为技术不行，而是因为做了一个没人要的东西。</p><p>这是我做AI产品3年最大的教训。技术很酷，但用户不关心酷不酷，用户关心有没有用。</p><p>我是怕浪猫，这章讲需求分析——怎么发现真正的需求，怎么验证需求是不是真的，怎么避免&quot;伪需求&quot;。</p><h2 id="_5-1-用户体验与产品设计基础" tabindex="-1">5.1 用户体验与产品设计基础 <a class="header-anchor" href="#_5-1-用户体验与产品设计基础" aria-label="Permalink to “5.1 用户体验与产品设计基础”">​</a></h2><h3 id="ai产品的用户体验有什么不同" tabindex="-1">AI产品的用户体验有什么不同 <a class="header-anchor" href="#ai产品的用户体验有什么不同" aria-label="Permalink to “AI产品的用户体验有什么不同”">​</a></h3><p>AI产品的用户体验和传统产品有本质区别：传统产品的行为是确定的，AI产品的行为是概率性的。这带来几个独特的UX挑战：</p><p><strong>1. 不确定性体验</strong> 用户不知道AI会给出什么回答，这种不确定性会带来焦虑。好的设计应该降低这种焦虑。</p><p>具体做法：</p><ul><li>给AI的输出加上&quot;置信度提示&quot;（&quot;我比较确定/我需要再查一下&quot;）</li><li>让用户可以方便地重新生成</li><li>提供编辑AI输出的能力，让用户觉得有掌控感</li><li>在AI思考时展示过程（流式输出的意义不只是快，还有&quot;它在思考&quot;的感知）</li></ul><p><strong>2. 错误处理体验</strong> AI一定会犯错。好的设计不是避免错误，而是让错误的影响最小化。</p><table tabindex="0"><thead><tr><th>错误类型</th><th>用户感受</th><th>设计策略</th></tr></thead><tbody><tr><td>完全正确的回答</td><td>满意</td><td>保持</td></tr><tr><td>小瑕疵但可接受</td><td>还行</td><td>允许用户快速修改</td></tr><tr><td>明显错误但无害</td><td>失望</td><td>提供重新生成/反馈按钮</td></tr><tr><td>有害或冒犯性内容</td><td>愤怒</td><td>安全过滤+即时反馈通道</td></tr><tr><td>拒答正常问题</td><td>困惑</td><td>解释原因并提供替代方案</td></tr></tbody></table><p>每种错误类型的处理方式完全不同，产品经理需要针对每种类型设计专门的交互。最常见的错误是&quot;小瑕疵但可接受&quot;——这时候最有效的设计是让用户可以快速编辑AI输出，而不是重新生成一个可能同样有瑕疵的回答。</p><p><strong>3. 期望管理体验</strong> 用户对AI的期望往往是两极的：要么觉得AI无所不能，要么觉得AI一无是处。好的设计应该引导用户形成合理的期望。</p><p>期望管理的3个层次：</p><ul><li>事前提示：&quot;我是AI助手，可能会犯错&quot;——降低初始期望</li><li>事中展示：流式输出、思考过程——让用户了解AI在工作</li><li>事后验证：标注信息来源、提供事实核查入口——让用户有能力验证</li></ul><blockquote><p>AI产品的UX不是让AI显得更聪明，而是让用户觉得更可控。可控感比聪明感更重要。</p></blockquote><h3 id="用户体验要素" tabindex="-1">用户体验要素 <a class="header-anchor" href="#用户体验要素" aria-label="Permalink to “用户体验要素”">​</a></h3><p>Jesse James Garrett的经典用户体验5层模型，在AI产品中有新的含义：</p><p><strong>1. 战略层</strong> 用户想要什么？AI能提供什么？ AI产品的战略层需要额外考虑AI的能力边界。不是用户想要的AI都能做，也不是AI能做的用户都想要。战略层的核心是找到&quot;用户需求&quot;和&quot;AI能力&quot;的交集。</p><p><strong>2. 范围层</strong> 做什么？不做什么？ AI产品的范围层需要考虑一个特殊问题：AI的行为是不确定的，你怎么定义&quot;做什么&quot;和&quot;不做什么&quot;？答案是定义&quot;应该做什么&quot;和&quot;绝对不能做什么&quot;，中间地带靠提示词和约束来控制。</p><p><strong>3. 结构层</strong> 信息架构和交互流程 AI产品的交互流程通常比传统产品更灵活。传统产品是&quot;用户操作→系统响应&quot;的确定性流程，AI产品是&quot;用户表达意图→AI理解→AI执行→用户反馈&quot;的概率性流程。需要设计&quot;AI理解失败&quot;和&quot;AI执行失败&quot;的兜底流程。</p><p><strong>4. 框架层</strong> 界面布局和导航 AI产品的界面需要容纳&quot;不确定性&quot;。比如对话式产品的界面需要同时展示：用户输入区、AI输出区、操作区（重新生成、编辑、反馈）。</p><p><strong>5. 表现层</strong> 视觉设计 AI产品的视觉设计需要传递&quot;智能但不傲慢&quot;的感觉。太多科技感会让用户觉得高不可攀，太少又让人觉得不专业。</p><h3 id="ai产品的交互模式" tabindex="-1">AI产品的交互模式 <a class="header-anchor" href="#ai产品的交互模式" aria-label="Permalink to “AI产品的交互模式”">​</a></h3><p>目前主流的AI产品交互模式有3种：</p><p><strong>1. 对话式</strong> 代表产品：ChatGPT、Claude 优点：学习成本低，自然语言交互 缺点：对复杂任务效率低，用户需要反复描述上下文 适合场景：探索性任务、开放性问题、创作类任务</p><p>对话式的关键设计决策：</p><ul><li>是否支持多轮对话记忆？记忆保留多久？</li><li>对话历史怎么管理？是否可搜索？</li><li>用户的输入方式是否只有文本？是否支持语音、图片？</li></ul><p><strong>2. 嵌入式</strong> 代表产品：Cursor、Notion AI、Github Copilot 优点：在用户工作流中无缝使用，无需切换 缺点：能力受限于嵌入场景 适合场景：日常工作辅助、编辑场景、开发场景</p><p>嵌入式的关键设计决策：</p><ul><li>触发方式：自动触发还是手动触发？</li><li>交互入口：悬浮按钮、侧边栏、还是行内？</li><li>上下文获取：AI能自动感知当前工作内容吗？</li></ul><p><strong>3. 工作流式</strong> 代表产品：Dify工作流、Zapier AI 优点：流程清晰可控，结果可预测 缺点：灵活性差，只能处理预定义的流程 适合场景：标准化流程、批量处理、需要确定性的任务</p><p>工作流式的关键设计决策：</p><ul><li>流程的可视化程度：用户能看到执行到哪一步吗？</li><li>失败处理：某一步失败后怎么恢复？</li><li>人工介入点：哪些步骤需要人工确认？</li></ul><table tabindex="0"><thead><tr><th>交互模式</th><th>适合场景</th><th>不适合场景</th></tr></thead><tbody><tr><td>对话式</td><td>探索性任务、开放性问题</td><td>重复性任务、精确操作</td></tr><tr><td>嵌入式</td><td>日常工作辅助</td><td>复杂多步骤任务</td></tr><tr><td>工作流式</td><td>标准化流程</td><td>需要灵活调整的任务</td></tr></tbody></table><p>选择建议：MVP阶段从对话式开始（开发成本最低），后续根据用户反馈决定是否需要嵌入式或工作流式。很多成功的AI产品最终是混合模式——简单问题用对话，复杂任务用工作流，日常辅助用嵌入式。</p><h2 id="_5-2-用户需求调研" tabindex="-1">5.2 用户需求调研 <a class="header-anchor" href="#_5-2-用户需求调研" aria-label="Permalink to “5.2 用户需求调研”">​</a></h2><h3 id="ai产品的需求有什么特殊之处" tabindex="-1">AI产品的需求有什么特殊之处 <a class="header-anchor" href="#ai产品的需求有什么特殊之处" aria-label="Permalink to “AI产品的需求有什么特殊之处”">​</a></h3><p>AI产品的需求调研比传统产品多了一个维度：不仅要了解用户需要什么，还要评估AI能不能做好。</p><p>传统产品的需求可行性评估：技术上能不能实现？ AI产品的需求可行性评估：技术上能不能实现 + AI能不能达到可接受的质量？</p><p>这就需要产品经理同时理解用户和技术两边。只懂用户不懂技术，会做出AI做不到的需求；只懂技术不懂用户，会做出没人要的功能。</p><h3 id="用户访谈" tabindex="-1">用户访谈 <a class="header-anchor" href="#用户访谈" aria-label="Permalink to “用户访谈”">​</a></h3><p>用户访谈是最经典也最有效的需求调研方法。但AI产品访谈有特殊技巧：</p><p><strong>访谈前的准备：</strong></p><ol><li>明确访谈目标 不是&quot;了解用户需求&quot;，而是具体的：</li></ol><ul><li>&quot;了解用户在XX场景中的完整工作流程&quot;</li><li>&quot;了解用户对现有AI产品的满意度和不满&quot;</li><li>&quot;验证用户是否有XX需求，以及这个需求的优先级&quot;</li></ul><ol start="2"><li>选择受访者</li></ol><ul><li>目标用户而非任意用户</li><li>8-12人即可，不需要太多</li><li>覆盖不同细分群体（新手/专家，不同行业，不同规模）</li></ul><ol start="3"><li>准备访谈提纲 提纲不是问卷，是引导对话的框架：</li></ol><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>开场（5分钟）</span></span>
<span class="line"><span>- 自我介绍和访谈目的</span></span>
<span class="line"><span>- 强调没有对错答案</span></span>
<span class="line"><span>- 录音许可</span></span>
<span class="line"><span></span></span>
<span class="line"><span>背景了解（10分钟）</span></span>
<span class="line"><span>- 请描述你日常工作中的XX流程</span></span>
<span class="line"><span>- 这个流程中你花时间最多的是什么？</span></span>
<span class="line"><span>- 最让你头疼的是什么？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>深入探索（20分钟）</span></span>
<span class="line"><span>- 刚才提到XX让你头疼，能具体说说吗？</span></span>
<span class="line"><span>- 你现在是怎么解决的？</span></span>
<span class="line"><span>- 如果有一个AI工具能帮你做XX，你觉得最重要的是什么？</span></span>
<span class="line"><span>- 你之前用过AI产品吗？体验怎么样？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>验证与反馈（10分钟）</span></span>
<span class="line"><span>- 如果有这样的工具，你愿意付费吗？付多少？</span></span>
<span class="line"><span>- 你觉得这个工具最可能让你失望的地方是什么？</span></span>
<span class="line"><span>- 你会推荐给同事吗？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结束（5分钟）</span></span>
<span class="line"><span>- 还有什么想补充的？</span></span>
<span class="line"><span>- 后续可以再联系你吗？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><p><strong>访谈执行技巧：</strong></p><ol><li>多问&quot;为什么&quot;，少问&quot;要不要&quot; 用户说&quot;我需要一个AI帮我写报告&quot;，不要直接记录这个需求，而是追问：</li></ol><ul><li>&quot;你现在写报告最费时间的部分是什么？&quot;</li><li>&quot;你希望AI帮你写整篇报告还是只写某些部分？&quot;</li><li>&quot;你写报告时最怕AI出错的是什么？&quot;</li></ul><ol start="2"><li><p>关注用户的痛点，而不是解决方案 用户提出的解决方案往往不是最优解。比如用户说&quot;我需要一个AI自动分类邮件&quot;，但真正的痛点可能是&quot;我每天花太多时间处理邮件&quot;。解决方案可能是AI自动分类，也可能是更好的过滤规则，也可能是减少邮件数量。</p></li><li><p>注意用户的非语言信号 犹豫、皱眉、叹气——这些往往比言语更有信息量。</p></li></ol><p><strong>用AI辅助访谈：</strong></p><p>AI可以加速访谈的前后两个环节：</p><p>用AI生成访谈提纲：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我需要做一次用户访谈，了解目标用户在[XX场景]中的需求和痛点。</span></span>
<span class="line"><span>目标用户是[用户画像]。</span></span>
<span class="line"><span>请帮我生成一个30分钟的访谈提纲，包含：开场、背景了解、深入探索、验证反馈、结束5个部分。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>用AI整理访谈洞察： 把访谈录音转成文字后，让AI帮提取关键洞察：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>以下是一份用户访谈记录。请提取：</span></span>
<span class="line"><span>1. 用户的核心痛点（按严重程度排序）</span></span>
<span class="line"><span>2. 用户提到的需求（按频率排序）</span></span>
<span class="line"><span>3. 用户对AI的期望和担忧</span></span>
<span class="line"><span>4. 潜在的产品机会</span></span>
<span class="line"><span></span></span>
<span class="line"><span>访谈记录：{transcript}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="问卷调研" tabindex="-1">问卷调研 <a class="header-anchor" href="#问卷调研" aria-label="Permalink to “问卷调研”">​</a></h3><p>问卷适合量化验证访谈中发现的假设。不适合发现新需求。</p><p><strong>问卷设计原则：</strong></p><p>原则一：一个问题只问一件事 错误：&quot;你觉得AI客服的回答准确且及时吗？&quot;（同时问了两件事） 正确：拆成两个问题——&quot;你觉得AI客服的回答准确吗？&quot;和&quot;你觉得AI客服的响应速度怎么样？&quot;</p><p>原则二：选项要穷尽且互斥 错误：满意度只给&quot;满意&quot;&quot;不满意&quot;两个选项 正确：1-5分，从非常不满意到非常满意</p><p>原则三：先易后难 先问简单的事实性问题（职业、使用频率），再问需要思考的态度性问题（满意度、付费意愿）。</p><p>原则四：不要诱导 错误：&quot;AI客服可以大大提升效率，你觉得这个功能重要吗？&quot; 正确：&quot;以下功能你认为是重要的请打勾：___&quot;</p><p><strong>AI产品的问卷特殊项：</strong></p><p>除了常规的人口统计和使用习惯问题，AI产品问卷还需要测量：</p><ol><li>AI信任度</li></ol><ul><li>&quot;你会直接使用AI给出的回答吗？&quot;（1-5分）</li><li>&quot;你会验证AI回答的准确性吗？&quot;（1-5分）</li><li>&quot;你觉得AI在[特定场景]中可靠吗？&quot;（1-5分）</li></ul><ol start="2"><li>容错接受度</li></ol><ul><li>&quot;AI犯错时你能接受吗？&quot;（1-5分）</li><li>&quot;你能接受的AI错误频率是多少？&quot;（每周1次/每月1次/几乎不能接受）</li></ul><ol start="3"><li>AI期望值</li></ol><ul><li>&quot;你对AI回答的准确率有什么期望？&quot;（&gt;95%/90%/80%/70%）</li><li>&quot;你希望AI在不确定时怎么做？&quot;（直接回答/告诉你不确定/给你多个选项/不回答）</li></ul><p><strong>抽样策略：</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>适用场景</th><th>优缺点</th></tr></thead><tbody><tr><td>便利抽样</td><td>快速验证</td><td>样本可能有偏差</td></tr><tr><td>配额抽样</td><td>确保群体覆盖</td><td>需要预先了解群体比例</td></tr><tr><td>滚雪球抽样</td><td>找特定人群</td><td>可能形成同质化样本</td></tr><tr><td>随机抽样</td><td>最可靠</td><td>成本高，执行难</td></tr></tbody></table><p>实际建议：至少收集100份有效问卷，1000份以上可以做细分分析。质量比数量重要——100份高质量的问卷比1000份垃圾问卷有用。</p><p><strong>用AI设计问卷：</strong></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我需要设计一份问卷，调研[目标用户]对[AI产品概念]的需求和接受度。</span></span>
<span class="line"><span>目标用户画像：{描述}</span></span>
<span class="line"><span>产品概念：{描述}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请帮我设计一份15-20题的问卷，包含：</span></span>
<span class="line"><span>1. 基本信息部分（3-4题）</span></span>
<span class="line"><span>2. 场景与痛点部分（5-6题）</span></span>
<span class="line"><span>3. AI接受度部分（4-5题）</span></span>
<span class="line"><span>4. 使用习惯部分（3-4题）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每题提供选项，并说明选择该题型的理由。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="_5-3-竞品调研" tabindex="-1">5.3 竞品调研 <a class="header-anchor" href="#_5-3-竞品调研" aria-label="Permalink to “5.3 竞品调研”">​</a></h2><h3 id="竞品选择" tabindex="-1">竞品选择 <a class="header-anchor" href="#竞品选择" aria-label="Permalink to “竞品选择”">​</a></h3><p>AI产品的竞品不只有直接竞品，还有3类：</p><table tabindex="0"><thead><tr><th>竞品类型</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>直接竞品</td><td>同赛道同功能</td><td>你做AI客服，竞品也做AI客服</td></tr><tr><td>替代竞品</td><td>不同方案解决同一问题</td><td>你做AI客服，竞品做规则客服系统</td></tr><tr><td>潜在竞品</td><td>还没做但可能做</td><td>大厂可能在你的赛道做AI功能</td></tr><tr><td>跨界竞品</td><td>技术相似但场景不同</td><td>你做AI客服，竞品用同样技术做AI销售</td></tr></tbody></table><p>最容易忽视的是替代竞品和潜在竞品。很多AI产品不是被直接竞品打败的，而是被传统方案或大厂免费功能替代的。</p><h3 id="竞品分析框架" tabindex="-1">竞品分析框架 <a class="header-anchor" href="#竞品分析框架" aria-label="Permalink to “竞品分析框架”">​</a></h3><p>对每个竞品，按以下框架分析：</p><p><strong>1. 产品定位</strong></p><ul><li>目标用户是谁</li><li>核心价值主张是什么</li><li>和我们的差异在哪</li></ul><p><strong>2. 功能矩阵</strong></p><table tabindex="0"><thead><tr><th>功能</th><th>我们</th><th>竞品A</th><th>竞品B</th></tr></thead><tbody><tr><td>知识问答</td><td>有</td><td>有</td><td>无</td></tr><tr><td>工具调用</td><td>有</td><td>无</td><td>有</td></tr><tr><td>多轮对话</td><td>有</td><td>有</td><td>有</td></tr><tr><td>数据分析</td><td>无</td><td>有</td><td>有</td></tr></tbody></table><p><strong>3. 技术方案</strong></p><ul><li>用的是什么大模型（自研/第三方API）</li><li>RAG还是微调</li><li>有没有Agent能力</li><li>数据安全怎么保障（本地部署/云端加密）</li></ul><p><strong>4. 用户评价</strong> 去用户聚集的地方看真实评价（小红书、知乎、App Store评论、ProductHunt）：</p><ul><li>好评集中在什么功能</li><li>差评集中在什么问题</li><li>用户最想要但竞品没有的功能是什么</li></ul><p>用户评价分析的技巧：</p><ul><li>差评比好评更有价值——它告诉你竞品没做好什么</li><li>注意差评的趋势——是功能问题还是体验问题</li><li>特别关注&quot;用了XX之后就不想用这个了&quot;的评价——这暗示了替代方案</li></ul><p><strong>5. 商业模式</strong></p><ul><li>免费还是付费</li><li>按量还是按月</li><li>有没有免费额度</li><li>增值服务的定价策略</li></ul><h3 id="用ai加速竞品分析" tabindex="-1">用AI加速竞品分析 <a class="header-anchor" href="#用ai加速竞品分析" aria-label="Permalink to “用AI加速竞品分析”">​</a></h3><p>AI可以大幅加速竞品信息的收集和整理：</p><ol><li>自动收集竞品信息</li></ol><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请帮我收集以下竞品的信息：</span></span>
<span class="line"><span>竞品名称：{名称}</span></span>
<span class="line"><span>需要收集：产品定位、核心功能、定价、用户评价</span></span>
<span class="line"><span>请从公开信息中整理，标注信息来源。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ol start="2"><li>自动化竞品对比</li></ol><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>以下是3个竞品的信息：</span></span>
<span class="line"><span>竞品A：{信息}</span></span>
<span class="line"><span>竞品B：{信息}</span></span>
<span class="line"><span>竞品C：{信息}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请从以下维度对比：</span></span>
<span class="line"><span>1. 功能覆盖度</span></span>
<span class="line"><span>2. 定价竞争力</span></span>
<span class="line"><span>3. 用户口碑</span></span>
<span class="line"><span>4. 技术方案差异</span></span>
<span class="line"><span>5. 市场定位差异</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="差异化策略" tabindex="-1">差异化策略 <a class="header-anchor" href="#差异化策略" aria-label="Permalink to “差异化策略”">​</a></h3><p>基于竞品分析，制定差异化策略：</p><p><strong>策略一：功能差异化</strong> 竞品没做的功能，你做。前提是这个功能用户真的需要，而不是&quot;竞品没想到&quot;但用户也不需要的功能。</p><p><strong>策略二：体验差异化</strong> 同样的功能，你做得更好用。比如更快的响应速度、更准确的回答、更友好的交互。体验差异化的关键是找到竞品最被用户诟病的点，做到极致。</p><p><strong>策略三：场景差异化</strong> 不做大而全，做小而精。在一个细分场景做到最好。比如不做通用AI客服，专门做电商退货场景的AI客服。场景差异化是最可持续的策略——因为大而全的产品很难在每个细分场景都做到最好。</p><p><strong>策略四：定价差异化</strong> 更便宜或者免费。但要注意，价格战不是长期策略。除非你有明显的成本优势（比如自研模型），否则低价策略不可持续。</p><blockquote><p>竞品分析的目的不是抄竞品，是找到竞品没做好的地方，做到更好。</p></blockquote><h2 id="_5-4-需求验证" tabindex="-1">5.4 需求验证 <a class="header-anchor" href="#_5-4-需求验证" aria-label="Permalink to “5.4 需求验证”">​</a></h2><h3 id="什么是伪需求" tabindex="-1">什么是伪需求 <a class="header-anchor" href="#什么是伪需求" aria-label="Permalink to “什么是伪需求”">​</a></h3><p>伪需求的3种类型：</p><ol><li><strong>自嗨型</strong> 产品经理觉得用户需要，但用户并不需要</li><li><strong>低频型</strong> 用户确实有这个需求，但频率极低，不值得开发</li><li><strong>能力不足型</strong> 用户有需求，但当前AI能力做不好，强行做出来体验差</li></ol><h3 id="需求验证方法" tabindex="-1">需求验证方法 <a class="header-anchor" href="#需求验证方法" aria-label="Permalink to “需求验证方法”">​</a></h3><p><strong>方法一：5Why验证法</strong> 对每个需求连续问5个&quot;为什么&quot;，如果问不到底就说明需求不够真实。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>需求：用户需要一个AI写作助手</span></span>
<span class="line"><span>为什么？因为用户写文章花时间</span></span>
<span class="line"><span>为什么花时间？因为不知道怎么组织内容</span></span>
<span class="line"><span>为什么不知道组织？因为缺乏写作框架</span></span>
<span class="line"><span>为什么缺乏框架？因为没有系统学习过写作方法</span></span>
<span class="line"><span>为什么没学习？因为没时间学，只需要偶尔写写</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结论：真正的需求不是&quot;AI帮我写&quot;，而是&quot;给我一个写作框架让我快速成文&quot;。</span></span>
<span class="line"><span>这可能意味着产品不应该自动生成全文，而是提供结构化的写作模板和素材推荐。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>方法二：烟雾测试（Smoke Test）</strong> 做一个假的产品落地页，看看有多少人愿意注册或付费。如果连假页面都没人注册，说明需求不成立。</p><p>落地页的核心元素：</p><ul><li>一句话产品描述</li><li>3-5个核心功能</li><li>价格或&quot;加入等待列表&quot;按钮</li><li>用户反馈入口</li></ul><p>衡量指标：</p><ul><li>页面访问→注册的转化率 &gt;5% 说明需求值得探索</li><li>注册→付费的转化率 &gt;1% 说明需求有商业价值</li></ul><p><strong>方法三：最小可行产品（MVP）验证</strong> 用最低成本做一个能验证核心假设的产品。不需要完美的UI，不需要全部功能，只需要验证&quot;用户会不会用&quot;。</p><p>AI产品的MVP特殊考虑：</p><ul><li>可以先用通用大模型API，不需要自研模型</li><li>可以先人工处理部分逻辑（Wizard of Oz方法），不需要全部自动化</li><li>可以先用对话式交互，不需要复杂的UI</li><li>可以先覆盖一个场景，不需要全场景</li></ul><p><strong>方法四：数据验证</strong> 如果已有类似产品或功能，用数据验证需求：</p><ul><li>用户使用频率</li><li>用户留存率</li><li>用户付费转化率</li><li>用户推荐意愿</li></ul><blockquote><p>需求验证的核心是&quot;用最低成本证明需求存在&quot;。不需要完美地满足需求，只需要证明需求是真实的、有价值的。</p></blockquote><p><strong>本章小结</strong></p><table tabindex="0"><thead><tr><th>主题</th><th>核心要点</th></tr></thead><tbody><tr><td>AI产品UX</td><td>不确定性体验、错误处理、期望管理是3大独特挑战</td></tr><tr><td>UX五层</td><td>战略→范围→结构→框架→表现，每层都要考虑AI的特殊性</td></tr><tr><td>交互模式</td><td>对话式/嵌入式/工作流式，MVP从对话式开始</td></tr><tr><td>需求调研</td><td>场景比需求真实，行为比语言可靠</td></tr><tr><td>用户访谈</td><td>多问为什么，关注痛点而非解决方案</td></tr><tr><td>问卷调研</td><td>不问技术问体验，测信任度和容错接受度</td></tr><tr><td>竞品调研</td><td>4类竞品+5维分析，找差异化而非抄功能</td></tr><tr><td>需求验证</td><td>5Why+烟雾测试+MVP+数据，用最低成本验证</td></tr></tbody></table><p>觉得有用？收藏起来，下次直接照抄。</p><p>你做AI产品调研时用什么方法？评论区聊聊。</p><p>关注怕浪猫，下期我们讲产品设计——从市场选择到数据驱动的产品迭代。</p><p>系列进度 5/13</p><p><strong>下章预告：</strong> 第6章产品打造，AI产品市场选择原则、设计原则、数据驱动迭代方法论。</p>`,138)])])}const h=a(p,[["render",i]]);export{c as __pageData,h as default};
